import React, { useEffect, useState, useContext } from 'react';
import axios from 'axios';
import { useNavigate, useParams } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const EditProduct = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, logout } = useContext(AuthContext || {});

  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [error, setError] = useState('');

// Gọi khi load trang
useEffect(() => {
  const fetchProduct = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/products/${id}`);
      console.log("Kết quả sản phẩm API trả về:", res.data);

      const p = res.data.product || res.data;

      setFormData({
        sku: p.sku || '',
        name: p.name || '',
        shortDescription: p.shortDescription || '',
        description: p.description || '',
        flowerType: p.flowerType || '',
        season: p.season || 'Quanh năm',
        categoryId: p.category?._id || '',
        price: p.price || '',
        discountPrice: p.discountPrice || '',
        stock: p.stock || 0,
        isFeatured: p.isFeatured || false,
        tagsInput: (p.tags || []).join(', '),
        tags: p.tags || [],
      });
      setCurrentImages(p.images || []);
    } catch (err) {
      console.error(err);
      setError('Không thể tải dữ liệu sản phẩm.');
    } finally {
      setFetching(false);
    }
  };

  fetchProduct();
}, [id]);


  // Images
  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [currentImages, setCurrentImages] = useState([]);

  // 🧮 Tính phần trăm giảm
  const discountPercent =
    formData.price && formData.discountPrice
      ? Math.min(Math.round(((formData.price - formData.discountPrice) / formData.price) * 100), 99)
      : 0;

// 🟢 Load product data (thông tin cũ)
const fetchProduct = async () => {
  try {
    const res = await axios.get(`${API_URL}/api/products/${id}`);
    console.log("Kết quả API trả về:", res.data);

    // Kiểm tra dữ liệu trả về (tránh undefined)
    const p = res.data.product || res.data;

    setFormData({
      sku: p.sku || '',
      name: p.name || '',
      shortDescription: p.shortDescription || '',
      description: p.description || '',
      flowerType: p.flowerType || '',
      season: p.season || 'Quanh năm',
      categoryId: p.category?._id || '',
      price: p.price || '',
      discountPrice: p.discountPrice || '',
      stock: p.stock || 0,
      isFeatured: p.isFeatured || false,
      tagsInput: (p.tags || []).join(', '),
      tags: p.tags || [],
    });

    setCurrentImages(p.images || []);
  } catch (err) {
    console.error(err);
    setError('Không thể tải dữ liệu sản phẩm.');
  } finally {
    setFetching(false);
  }
};





  // 🟢 Load danh mục
  useEffect(() => {
    const fetchCats = async () => {
      try {
        const res = await axios.get(`${API_URL}/api/categories`);

        const cats = Array.isArray(res.data) ? res.data : res.data.categories || [];
        setCategories(cats);
      } catch (err) {
        console.error('Load categories error', err);
      }
    };
    fetchCats();
  }, []);

  // 🟢 Cập nhật tags khi người dùng nhập
  useEffect(() => {
    const arr = formData.tagsInput
      .split(',')
      .map((t) => t.trim())
      .filter((t) => t);
    setFormData((prev) => ({ ...prev, tags: arr }));
  }, [formData.tagsInput]);

  // 🟢 Tạo preview ảnh mới
  useEffect(() => {
    if (!files.length) return setPreviews([]);
    const urls = files.map((file) => URL.createObjectURL(file));
    setPreviews(urls);
    return () => urls.forEach((u) => URL.revokeObjectURL(u));
  }, [files]);

  // 🟢 Xử lý input
  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  // 🟢 Chọn file mới (nếu có)
  const handleFilesChange = (e) => {
    const selected = Array.from(e.target.files);
    if (selected.length > 5) {
      alert('Tối đa 5 ảnh thôi nhé 🌸');
      return;
    }
    setFiles(selected);
  };

  const getToken = () => {
    try {
      return user?.token || JSON.parse(localStorage.getItem('userInfo'))?.token;
    } catch {
      return null;
    }
  };

  // 🟢 Gửi form cập nhật
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    const { name, price, categoryId, description, sku } = formData;
    if (!name || !price || !categoryId || !description || !sku) {
      setError('Vui lòng điền đầy đủ các trường có dấu *');
      return;
    }

    if (Number(formData.discountPrice) >= Number(formData.price)) {
      setError('Giá khuyến mãi phải nhỏ hơn giá gốc');
      return;
    }

    const token = getToken();
    if (!token) {
      alert('Phiên đăng nhập đã hết hạn. Vui lòng đăng nhập lại.');
      if (logout) logout();
      return;
    }

    try {
      setLoading(true);
      let imageUrls = currentImages;

      // Nếu chọn ảnh mới → thay ảnh cũ
      if (files.length > 0) {
        const imgForm = new FormData();
        files.forEach((f) => imgForm.append('images', f));
        const uploadRes = await axios.post(`${API_URL}/api/upload`, imgForm, {
          headers: {
            'Content-Type': 'multipart/form-data',
            Authorization: `Bearer ${token}`,
          },
        });
        imageUrls = uploadRes.data.urls || [];
      }

      const payload = {
        ...formData,
        price: Number(formData.price),
        discountPrice: formData.discountPrice ? Number(formData.discountPrice) : undefined,
        stock: Number(formData.stock),
        tags: formData.tags,
        images: imageUrls,
      };

      await axios.put(`${API_URL}/api/products/${id}`, payload, {
        headers: { Authorization: `Bearer ${token}` },
      });

      // ✅ Không navigate, mà load lại dữ liệu mới nhất
      alert('🌸 Cập nhật sản phẩm thành công!');
      await fetchProduct(); // load lại dữ liệu để form giữ nguyên
    } catch (err) {
      console.error(err);
      setError(err?.response?.data?.message || 'Lỗi khi cập nhật sản phẩm.');
    } finally {
      setLoading(false);
    }
  };

  if (fetching)
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin w-10 h-10 border-4 border-pink-400 border-t-transparent rounded-full"></div>
      </div>
    );

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 to-blue-50 py-10 px-4">
      <div className="max-w-4xl mx-auto bg-white shadow-lg rounded-2xl p-8 border border-gray-100">
        <h2 className="text-3xl font-semibold text-gray-800 mb-6 text-center">🌸 Cập Nhật Sản Phẩm</h2>

        {error && <div className="mb-4 text-red-600 bg-red-100 border border-red-300 p-3 rounded-lg">{error}</div>}

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* SKU & Name */}
          <div className="grid grid-cols-2 gap-6">
            <div>
              <label className="block font-medium text-gray-700 mb-1">Mã sản phẩm *</label>
              <input
                name="sku"
                value={formData.sku}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition"
              />
            </div>
            <div>
              <label className="block font-medium text-gray-700 mb-1">Tên sản phẩm *</label>
              <input
                name="name"
                value={formData.name}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition"
              />
            </div>
          </div>

          {/* Mô tả ngắn */}
          <div>
            <label className="block font-medium text-gray-700 mb-1">Chi tiết sản phẩm</label>
            <textarea
              name="shortDescription"
              value={formData.shortDescription}
              onChange={handleChange}
              rows="3"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition"
            />
          </div>

          {/* Danh mục + loại hoa */}
          <div className="grid grid-cols-2 gap-6">
            <div>
              <label className="block font-medium text-gray-700 mb-1">Danh mục *</label>
              <select
                name="categoryId"
                value={formData.categoryId}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-blue-400 focus:ring focus:ring-blue-100 outline-none transition"
              >
                <option value="">Chọn danh mục</option>
                {categories.map((c) => (
                  <option key={c._id} value={c._id}>
                    {c.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block font-medium text-gray-700 mb-1">Loại hoa</label>
              <input
                name="flowerType"
                value={formData.flowerType}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-blue-400 focus:ring focus:ring-blue-100 outline-none transition"
              />
            </div>
          </div>

          {/* Giá */}
          <div className="grid grid-cols-2 gap-6">
            <div>
              <label className="block font-medium text-gray-700 mb-1">Giá gốc *</label>
              <input
                type="number"
                name="price"
                value={formData.price}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-green-400 focus:ring focus:ring-green-100 outline-none transition"
              />
            </div>

            <div>
              <label className="block font-medium text-gray-700 mb-1">Giá khuyến mãi</label>
              <input
                type="number"
                name="discountPrice"
                value={formData.discountPrice}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-green-400 focus:ring focus:ring-green-100 outline-none transition"
              />
              {discountPercent > 0 && (
                <p className="text-sm mt-1 text-green-600">
                  Giảm khoảng <span className="font-semibold">{discountPercent}%</span> so với giá gốc
                </p>
              )}
            </div>
          </div>

          {/* Mô tả */}
          <div>
            <label className="block font-medium text-gray-700 mb-1">Mô tả *</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              rows="5"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition"
            />
          </div>

          {/* Ảnh */}
          <div>
            <label className="block font-medium text-gray-700 mb-1">Hình ảnh (chọn mới để thay thế)</label>
            <input
              type="file"
              accept="image/*"
              multiple
              onChange={handleFilesChange}
              className="block w-full border border-gray-200 rounded-lg p-2 bg-gray-50 hover:bg-gray-100 cursor-pointer transition"
            />
            {currentImages.length > 0 && files.length === 0 && (
              <div className="mt-3 grid grid-cols-5 gap-3">
                {currentImages.map((img, i) => (
                  <img
                    key={i}
                    src={`${API_URL}${img}`}
                    alt=""
                    className="w-28 h-28 object-cover rounded-lg border border-gray-200 shadow-sm"
                  />
                ))}
              </div>
            )}
            {previews.length > 0 && (
              <div className="mt-3 grid grid-cols-5 gap-3">
                {previews.map((p, i) => (
                  <img
                    key={i}
                    src={p}
                    alt=""
                    className="w-28 h-28 object-cover rounded-lg border border-gray-200 shadow-sm"
                  />
                ))}
              </div>
            )}
          </div>

          {/* Tags + nổi bật */}
          <div className="flex flex-col gap-3">
            <div>
              <label className="block font-medium text-gray-700 mb-1">Từ khóa (cách nhau bằng dấu ,)</label>
              <input
                name="tagsInput"
                value={formData.tagsInput}
                onChange={handleChange}
                placeholder="hoa hồng, sinh nhật, dễ thương..."
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition"
              />
            </div>

            <div className="flex items-center gap-3">
              <input
                id="featured"
                type="checkbox"
                name="isFeatured"
                checked={formData.isFeatured}
                onChange={handleChange}
                className="w-4 h-4 accent-pink-500"
              />
              <label htmlFor="featured" className="text-gray-700">
                Sản phẩm nổi bật
              </label>
            </div>
          </div>

          {/* Buttons */}
          <div className="flex justify-end gap-3">
            <button
              type="button"
              onClick={() => navigate('/admin/products')}
              className="px-5 py-2 rounded-lg bg-gray-200 text-gray-700 hover:bg-gray-300 transition"
            >
              Hủy
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-2 rounded-lg bg-pink-500 text-white font-medium hover:bg-pink-600 shadow transition"
            >
              {loading ? 'Đang lưu...' : 'Cập nhật sản phẩm'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditProduct;
